var doc = uiapp.ActiveUIDocument.Document;
var selIds = uiapp.ActiveUIDocument.Selection.GetElementIds().ToList();
if (selIds.Count == 0) return new { updated = 0, note = "no selection; select an element with a Comments parameter" };
int updated = 0;
foreach (var id in selIds)
{
    var el = doc.GetElement(id);
    var p = el.LookupParameter("Comments");
    if (p != null && !p.IsReadOnly && p.StorageType == StorageType.String)
    {
        p.Set("AWARE touched on " + System.DateTime.UtcNow.ToString("o"));
        updated++;
    }
}
return new { updated = updated, selected = selIds.Count };
